class MainActivity : AppCompatActivity() {

    private lateinit var webView: WebView
    private lateinit var progressBar: ProgressBar

    // IMPORTANT: Replace with your mobile web app's URL
    private val WEB_APP_URL = "https://www.google.com" // Example: "https://your-mobile-web-app.com"

    private val CAMERA_PERMISSION_CODE = 101

    // Store the last permission request if it needs to be granted after user action
    private var pendingPermissionRequest: PermissionRequest? = null

    @SuppressLint("SetJavaScriptEnabled")
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main) // Make sure you have activity_main.xml with WebView and ProgressBar

        webView = findViewById(R.id.webView)
        progressBar = findViewById(R.id.progressBar)

        setupWebView()
        webView.loadUrl(WEB_APP_URL)
    }

    @SuppressLint("SetJavaScriptEnabled")
    private fun setupWebView() {
        webView.settings.apply {
            javaScriptEnabled = true
            domStorageEnabled = true // Enable HTML5 local storage
            databaseEnabled = true // Enable HTML5 database
            allowFileAccess = true
            allowContentAccess = true
            mediaPlaybackRequiresUserGesture = false // Allow media to autoplay
            loadWithOverviewMode = true
            useWideViewPort = true
            cacheMode = WebSettings.LOAD_DEFAULT // Use default cache behavior
            mixedContentMode = WebSettings.MIXED_CONTENT_ALWAYS_ALLOW // Allow http content on https pages
            userAgentString = userAgentString + " AndroidHybridApp" // Custom user agent if needed
        }

        // Add the JavaScript interface (the bridge)
        webView.addJavascriptInterface(AndroidBridge(this, webView), "AndroidBridge")

        webView.webViewClient = object : WebViewClient() {
            override fun onPageStarted(view: WebView?, url: String?, favicon: Bitmap?) {
                super.onPageStarted(view, url, favicon)
                progressBar.visibility = View.VISIBLE
            }

            override fun onPageFinished(view: WebView?, url: String?) {
                super.onPageFinished(view, url)
                progressBar.visibility = View.GONE
            }

            override fun onReceivedError(view: WebView?, request: WebResourceRequest?, error: WebResourceError?) {
                super.onReceivedError(view, request, error)
                if (request?.isForMainFrame == true) {
                    Toast.makeText(this@MainActivity, "Error loading page: ${error?.description}", Toast.LENGTH_LONG).show()
                    Log.e("WebViewWrapper", "Error loading page: ${error?.description} on URL: ${request?.url}")
                }
            }
        }

        webView.webChromeClient = object : WebChromeClient() {
            override fun onProgressChanged(view: WebView?, newProgress: Int) {
                super.onProgressChanged(view, newProgress)
                progressBar.progress = newProgress
            }

            override fun onJsAlert(view: WebView?, url: String?, message: String?, result: android.webkit.JsResult?): Boolean {
                Toast.makeText(this@MainActivity, message, Toast.LENGTH_SHORT).show()
                result?.confirm()
                return true
            }

            override fun onConsoleMessage(consoleMessage: ConsoleMessage?): Boolean {
                Log.d("WebViewConsole", "${consoleMessage?.message()} -- From line ${consoleMessage?.lineNumber()} of ${consoleMessage?.sourceId()}")
                return super.onConsoleMessage(consoleMessage)
            }

            override fun onGeolocationPermissionsShowPrompt(origin: String?, callback: GeolocationPermissions.Callback?) {
                // Auto-grant geolocation permissions
                callback?.invoke(origin, true, false)
            }

            override fun onPermissionRequest(request: PermissionRequest?) {
                if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.LOLLIPOP) {
                    val resources = request?.resources ?: arrayOf()
                    var needsCameraPermission = false
                    var needsAudioPermission = false

                    for (resource in resources) {
                        if (resource == PermissionRequest.RESOURCE_VIDEO_CAPTURE) {
                            needsCameraPermission = true
                        }
                        if (resource == PermissionRequest.RESOURCE_AUDIO_CAPTURE) {
                            needsAudioPermission = true
                        }
                    }

                    val permissionsToRequest = mutableListOf<String>()
                    if (needsCameraPermission && ContextCompat.checkSelfPermission(this@MainActivity, Manifest.permission.CAMERA) != PackageManager.PERMISSION_GRANTED) {
                        permissionsToRequest.add(Manifest.permission.CAMERA)
                    }
                    if (needsAudioPermission && ContextCompat.checkSelfPermission(this@MainActivity, Manifest.permission.RECORD_AUDIO) != PackageManager.PERMISSION_GRANTED) {
                        permissionsToRequest.add(Manifest.permission.RECORD_AUDIO)
                    }

                    if (permissionsToRequest.isNotEmpty()) {
                        pendingPermissionRequest = request // Store the request for later
                        ActivityCompat.requestPermissions(this@MainActivity, permissionsToRequest.toTypedArray(), CAMERA_PERMISSION_CODE)
                    } else {
                        // Permissions already granted or not needed, grant immediately
                        request?.grant(resources)
                    }
                }
            }
        }
    }

    override fun onBackPressed() {
        if (webView.canGoBack()) {
            webView.goBack()
        } else {
            super.onBackPressed()
        }
    }

    override fun onRequestPermissionsResult(requestCode: Int, permissions: Array<out String>, grantResults: IntArray) {
        super.onRequestPermissionsResult(requestCode, permissions, grantResults)
        if (requestCode == CAMERA_PERMISSION_CODE) {
            val allGranted = grantResults.all { it == PackageManager.PERMISSION_GRANTED }
            if (allGranted) {
                Log.d("WebViewWrapper", "Camera/Audio permissions granted by user.")
                pendingPermissionRequest?.grant(pendingPermissionRequest?.resources)
            } else {
                Log.d("WebViewWrapper", "Camera/Audio permissions denied by user.")
                Toast.makeText(this, "Camera/Microphone permission denied.", Toast.LENGTH_SHORT).show()
                pendingPermissionRequest?.deny()
            }
            pendingPermissionRequest = null // Clear the pending request
        }
    }

