class AndroidBridge(private val activity: Activity, private val webView: WebView) {

    private val TAG = "AndroidBridge"
    private val WEB_APP_STORAGE_KEY = "WebAppStorage"
    private val NOTIFICATION_CHANNEL_ID = "web_app_channel"

    // Generic JavaScript callback function
    // Web app should define: window.androidBridgeCallback = function(callbackId, success, data) { ... }
    private fun callJavaScriptCallback(callbackId: String, success: Boolean, data: String?) {
        val jsFunction = "window.androidBridgeCallback('$callbackId', $success, $data);"
        activity.runOnUiThread {
            webView.evaluateJavascript(jsFunction, null)
        }
    }

    @JavascriptInterface
    fun showToast(message: String) {
        activity.runOnUiThread {
            Toast.makeText(activity, message, Toast.LENGTH_SHORT).show()
        }
    }

    @JavascriptInterface
    fun log(message: String) {
        Log.d(TAG, message)
    }

    @JavascriptInterface
    fun requestCameraAccess(callbackId: String) {
        Log.d(TAG, "Web app requested camera access.")

        if (ContextCompat.checkSelfPermission(activity, Manifest.permission.CAMERA) == PackageManager.PERMISSION_GRANTED) {
            Log.d(TAG, "Camera permission already granted.")
            callJavaScriptCallback(callbackId, true, "'Camera access granted'")
        } else {
            Log.d(TAG, "Camera permission not granted. Requesting...")
            // The actual permission request must be triggered from the Activity context.
            // For a robust solution, MainActivity would have a method like `requestCameraPermission(callbackId)`
            // and `onRequestPermissionsResult` would then call `webView.evaluateJavascript`.
            // Here, we simulate by showing a toast and asking the user to grant manually,
            // then immediately denying the JS call. The WebChromeClient.onPermissionRequest handles
            // the WebView's internal camera/mic requests. This is for calls directly from the bridge.
            activity.runOnUiThread {
                Toast.makeText(activity, "Please grant camera permission in app settings if prompted.", Toast.LENGTH_LONG).show()
                ActivityCompat.requestPermissions(activity, arrayOf(Manifest.permission.CAMERA), (activity as MainActivity).CAMERA_PERMISSION_CODE)
                callJavaScriptCallback(callbackId, false, "'Camera access denied or not granted yet'")
            }
        }
    }

    @JavascriptInterface
    fun getLocalStorageItem(key: String, callbackId: String) {
        val sharedPreferences = activity.getSharedPreferences(WEB_APP_STORAGE_KEY, Context.MODE_PRIVATE)
        val value = sharedPreferences.getString(key, null)
        Log.d(TAG, "getLocalStorageItem: $key = $value")
        val result = value?.let { "'$it'" } ?: "null"
        callJavaScriptCallback(callbackId, true, result)
    }

    @JavascriptInterface
    fun setLocalStorageItem(key: String, value: String) {
        val sharedPreferences = activity.getSharedPreferences(WEB_APP_STORAGE_KEY, Context.MODE_PRIVATE)
        sharedPreferences.edit().putString(key, value).apply()
        Log.d(TAG, "setLocalStorageItem: $key = $value")
        // No explicit callback needed for setter, but could add one if desired.
    }

    @JavascriptInterface
    fun removeLocalStorageItem(key: String) {
        val sharedPreferences = activity.getSharedPreferences(WEB_APP_STORAGE_KEY, Context.MODE_PRIVATE)
        sharedPreferences.edit().remove(key).apply()
        Log.d(TAG, "removeLocalStorageItem: $key")
    }

    @JavascriptInterface
    fun showNotification(title: String, message: String, callbackId: String) {
        Log.d(TAG, "Web app requested notification: $title - $message")
        val notificationId = System.currentTimeMillis().toInt() // Unique ID for notification

        createNotificationChannel()

        val builder = NotificationCompat.Builder(activity, NOTIFICATION_CHANNEL_ID)
            .setSmallIcon(android.R.drawable.ic_dialog_info) // Use a default system icon
            .setContentTitle(title)
            .setContentText(message)
            .setPriority(NotificationCompat.PRIORITY_DEFAULT)
            .setAutoCancel(true) // Dismisses notification when tapped

        with(NotificationManagerCompat.from(activity)) {
            if (ActivityCompat.checkSelfPermission(activity, Manifest.permission.POST_NOTIFICATIONS) != PackageManager.PERMISSION_GRANTED) {
                // For Android 13+ (API 33), POST_NOTIFICATIONS permission is required
                // In a real app, you would request this permission.
                // For this example, we'll log a warning and not show the notification.
                Log.w(TAG, "POST_NOTIFICATIONS permission not granted. Cannot show notification on Android 13+.")
                callJavaScriptCallback(callbackId, false, "'Permission denied to show notification'")
                return
            }
            notify(notificationId, builder.build())
            Log.d(TAG, "Notification shown: $title")
            callJavaScriptCallback(callbackId, true, "'Notification shown'")
        }
    }

    private fun createNotificationChannel() {
        // Create the NotificationChannel, but only on API 26+ because
        // the NotificationChannel class is new and not in the support library
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            val name = "Web App Notifications"
            val descriptionText = "Notifications from the mobile web app"
            val importance = NotificationManager.IMPORTANCE_DEFAULT
            val channel = NotificationChannel(NOTIFICATION_CHANNEL_ID, name, importance).apply {
                description = descriptionText
            }
            // Register the channel with the system
            val notificationManager: NotificationManager =
                activity.getSystemService(Context.NOTIFICATION_SERVICE) as NotificationManager
            notificationManager.createNotificationChannel(channel)
        }
    }
}

